'use strict';

var $TypeError = require('es-errors/type');
var isNegativeZero = require('math-intrinsics/isNegativeZero');

var IsDetachedBuffer = require('./IsDetachedBuffer');

var isInteger = require('math-intrinsics/isInteger');
var typedArrayBuffer = require('typed-array-buffer');



module.exports = function IsValidIntegerIndex(O, index) {
	
	var buffer = typedArrayBuffer(O); 

	if (typeof index !== 'number') {
		throw new $TypeError('Assertion failed: Type(index) is not Number');
	}

	if (IsDetachedBuffer(buffer)) { return false; } 

	if (!isInteger(index)) { return false; } 

	if (isNegativeZero(index)) { return false; } 

	if (index < 0 || index >= O.length) { return false; } 

	return true; 
};
